 1	import {
 2	  Button,
 3	  Form,
 4	  FormGroup,
 5	  FormHelperText,
 6	  HelperText,
 7	  HelperTextItem,
 8	  Modal,
 9	  ModalVariant,
10	  TextInput,
11	} from "@patternfly/react-core";
12	import * as React from "react";
13	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
14	import { useField } from "formik";
15	
16	type CustomTypeModalProps = {
17	  onClose(): void;
18	  isOpen: boolean;
19	  fieldName: string;
20	};
21	
22	const CustomTypeModal: React.FC<CustomTypeModalProps> = ({
23	  fieldName,
24	  isOpen,
25	  onClose,
26	}) => {
27	  const { t } = useNodeHealthCheckTranslation();
28	  const [, , { setValue }] = useField(fieldName);
29	  const [customType, setCustomType] = React.useState<string>("");
30	  React.useEffect(() => {
31	    if (!isOpen) {
32	      setCustomType("");
33	    }
34	  }, [isOpen]);
35	
36	  return (
37	    <Modal
38	      isOpen={isOpen}
39	      onClose={onClose}
40	      variant={ModalVariant.small}
41	      title={t("Use custom type")}
42	      data-test="use-custom-type-modal"
43	      actions={[
44	        <Button
45	          key="confirm"
46	          variant="primary"
47	          onClick={() => {
48	            setValue(customType);
49	            onClose();
50	          }}
51	          isDisabled={!customType}
52	          data-test="confirm-custom-type"
53	          type="submit"
54	        >
55	          {t("Create")}
56	        </Button>,
57	        <Button
58	          key="cancel"
59	          variant="link"
60	          onClick={onClose}
61	          data-test="cancel-custom-type"
62	        >
63	          {t("Cancel")}
64	        </Button>,
65	      ]}
66	    >
67	      <Form>
68	        <FormGroup fieldId="custom-type" isRequired label={t("Type")}>
69	          <TextInput
70	            name={fieldName}
71	            value={customType}
72	            onChange={(_, value) => setCustomType(value)}
73	            data-test="custom-type-input"
74	            aria-label="custom type"
75	          />
76	          <FormHelperText>
77	            <HelperText>
78	              <HelperTextItem>{t("Name of the custom type")}</HelperTextItem>
79	            </HelperText>
80	          </FormHelperText>
81	        </FormGroup>
82	      </Form>
83	    </Modal>
84	  );
85	};
86	
87	export default CustomTypeModal;

